import React, { useState } from "react";
function FamilyDetails({ nextStep, prevStep, updateData }) {
 const [family, setFamily] = useState([]);
 const addMember = () => {
   setFamily([...family, { name: "", relation: "" }]);
 };
 const handleChange = (index, field, value) => {
   const updated = [...family];
   updated[index][field] = value;
   setFamily(updated);
 };
 return (
<div>
<h2>Family Details</h2>
     {family.map((member, i) => (
<div key={i}>
<input placeholder="Name" onChange={(e) => handleChange(i, "name", e.target.value)} />
<input placeholder="Relation" onChange={(e) => handleChange(i, "relation", e.target.value)} />
</div>
     ))}
<button onClick={addMember}>Add Member</button>
<button onClick={prevStep}>Back</button>
<button onClick={() => { updateData({ family }); nextStep(); }}>Next</button>
</div>
 );
}
export default FamilyDetails;